export default function BottomTabBar() {
  const pathname = usePathname();
  const active: "face" | "vein" | "settings" = pathname.startsWith("/vein") ? "vein" : pathname === "/login" ? "settings" : "face";
  const { lang } = useLanguage();
  const { logout } = useApiKey();
  const tx = translations[lang];

  const iconSize = "clamp(22px, 5.5vw, 28px)";
  const labelSize = "clamp(12px, 3.2vw, 15px)";
  const tabHeight = "clamp(72px, 17vw, 86px)";

  return (
    <nav
      className="fixed bottom-0 bg-white border-t border-[#e2e8f0] z-10"
      style={{
        left: "50%",
        transform: "translateX(-50%)",
        width: "min(500px, 100vw)",
      }}
    >
      <div className="flex" style={{ height: tabHeight }}>

        {/* 얼굴 인증 */}
        <Link href="/" className="flex-1 flex flex-col items-center justify-center gap-[7px]">
          {active === "face" ? (
            <div
              className="flex items-center justify-center rounded-lg bg-[#EFF9FF]"
              style={{ width: "clamp(32px, 8vw, 40px)", height: "clamp(28px, 7vw, 36px)" }}
            >
              <span style={{ width: iconSize, height: iconSize, display: "flex" }}>
                <FaceIdIcon color="#006FFF" />
              </span>
            </div>
          ) : (
            <span style={{ width: iconSize, height: iconSize, display: "flex" }}>
              <FaceIdIcon color="#64748B" />
            </span>
          )}
          <span
            style={{
              color: active === "face" ? "#006FFF" : "#64748B",
              fontWeight: active === "face" ? 600 : 400,
              fontSize: labelSize,
              letterSpacing: "-0.35px",
              lineHeight: 1,
            }}
          >
            {tx.tabFaceAuth}
          </span>
          {active === "face" && (
            <span style={{ marginTop: "2px", display: "flex" }}>
              <svg width="5" height="5" viewBox="0 0 5 5" fill="none">
                <circle cx="2.5" cy="2.5" r="2.5" fill="#006FFF" />
              </svg>
            </span>
          )}
        </Link>

        {/* 지정맥 인증 */}
        <Link href="/vein" className="flex-1 flex flex-col items-center justify-center gap-[7px]">
          {active === "vein" ? (
            <div
              className="flex items-center justify-center rounded-lg bg-[#EFF9FF]"
              style={{ width: "clamp(34px, 8.5vw, 44px)", height: "clamp(30px, 7.5vw, 38px)" }}
            >
              <span style={{ width: iconSize, height: iconSize, display: "flex" }}>
                <VeinIcon color="#006FFF" />
              </span>
            </div>
          ) : (
            <span style={{ width: iconSize, height: iconSize, display: "flex" }}>
              <VeinIcon color="#64748B" />
            </span>
          )}
          <span
            style={{
              color: active === "vein" ? "#006FFF" : "#64748B",
              fontWeight: active === "vein" ? 600 : 400,
              fontSize: labelSize,
              letterSpacing: "-0.325px",
              lineHeight: 1,
            }}
          >
            {tx.tabVeinAuth}
          </span>
          {active === "vein" && (
            <span style={{ marginTop: "2px", display: "flex" }}>
              <svg width="5" height="5" viewBox="0 0 5 5" fill="none">
                <circle cx="2.5" cy="2.5" r="2.5" fill="#006FFF" />
              </svg>
            </span>
          )}
        </Link>

        {/* API Key / 로그아웃 */}
        <button
          onClick={() => { if (window.confirm(tx.logoutConfirm)) logout(); }}
          className="flex-1 flex flex-col items-center justify-center gap-[7px]"
        >
          <span style={{ width: iconSize, height: iconSize, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#64748B" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
              <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
              <polyline points="16 17 21 12 16 7"/>
              <line x1="21" y1="12" x2="9" y2="12"/>
            </svg>
          </span>
          <span
            style={{
              color: "#64748B",
              fontWeight: 400,
              fontSize: labelSize,
              letterSpacing: "-0.325px",
              lineHeight: 1,
            }}
          >
            {lang === "ko" ? "로그아웃" : "Logout"}
          </span>
        </button>

      </div>
    </nav>
  );
}
